1	type Item = { type: string };
2	
3	type QuoteStep = { op: "quote"; items: Item[] };
4	
5	export type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: Array<Record<string, unknown>>;
8	};
9	
10	export type ScenarioResult = {
11	  results: Array<Record<string, unknown>>;
12	};
13	
14	const PROCESSING_FEE = 5;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	};
19	
20	const quotePremium = (items: Item[]): number => {
21	  const total = items.reduce((sum, item) => {
22	    const base = BASE_PREMIUMS[item.type] ?? 0;
23	    const firstInsurance = base / 10;
24	    return sum + base + firstInsurance;
25	  }, 0);
26	  return Math.ceil(total + PROCESSING_FEE);
27	};
28	
29	export const runScenario = (scenario: Scenario): ScenarioResult => {
30	  const results = scenario.steps.map((step) => {
31	    const quote = step as unknown as QuoteStep;
32	    return { premium: quotePremium(quote.items) };
33	  });
34	  return { results };
35	};
